{
  "意圖": "以單一動畫角色為主題的特定黑板藝術作品進行寫實紀錄，捕捉該媒介在教室情境中短暫的特質。",
  "框架": {
    "aspect_ratio": "4:3",
    "構圖": "一個聚焦於黑板壁畫的中景鏡頭。構圖中將教師的桌子置於前景以增加比例，單一角色的藝術作品主導背景空間。",
    "style_mode": "documentary_realism、注重質感、氛圍自然主義"
  },
  "主旨": {
    "primary_subject": "一幅大型、精緻的粉筆畫，描繪《海賊王》的海賊女帝「波雅．漢考克」在標準綠色教室黑板上。",
    "visual_details": "插圖展現漢考克以自信傲然的站姿示人，微抬下巴，流露高傲美貌與不可一世的魅力。黑色及腰長髮以細膩的深色粉筆層次描繪，髮尾略帶飄動感。她身穿招牌的紅色旗袍式暴露服，深V設計與大腿側開衩以紅、粉、白色粉筆刻畫出光澤與布料的柔軟。胸前及裙襬的金色與孔雀羽毛圖案以亮黃色點綴，呈現華麗細節。外搭披風般的白色海賊斗篷，以流暢白色與灰色粉筆線呈現布料折線。她一手放在腰側，另一手高舉，指尖流轉著以粉紅與白色粉筆繪製的愛心能量，象徵她的甜甜果實能力。臉部特徵保留她美艷的紫羅蘭雙眸與心形耳環，細緻陰影表現出立體感與尊貴氣場。",
    "medium_texture": "影像保留粉筆顆粒感與細緻粉塵痕跡。陰影與交叉陰影筆觸強調布料起伏、身形曲線與髮絲層次。局部彩粉混合在綠色黑板上產生柔和過渡，尤其是在肌膚與愛心光效中。",
    "surrounding_elements": "角色左側以白色粉筆直排書寫：「海賊女帝 波雅・漢考克」，呈現強烈主題識別。"
  },
  "環境": {
    "地點": "標準的日本學校教室。",
    "foreground_elements": "一張木製教師桌位於前景下方，桌上散落著紅、粉、白、黃粉筆棒，以及一個粉筆擦，邊緣覆有粉塵。",
    "background_elements": "綠色黑板橫跨整個畫面，被金屬粉筆盤框住底部。側牆面以米白色灰泥呈現，搭配一個小型喇叭箱，暗示一般教室配置。",
    "氛圍": "靜謐無人，保留作品創作後剛完成的安靜與神聖感，彷彿令人敬畏海賊女帝的存在感。"
  },
  "閃電": {
    "類型": "教室環境光擴散。",
    "品質": "由頭頂螢光燈的均勻照明與左側窗戶自然光混合，光線柔和無眩光，突顯粉筆質感與紅色禮服的華麗。",
    "color_temperature": "中性白色約 5000K，準確呈現漢考克膚色、紅色禮服與白色披風。",
